import { Anthropic } from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: 'your_key' });

const tools = [
  {
    name: 'web_search',
    description: 'Search current web for research',
    inputSchema: {
      type: 'object',
      properties: { query: { type: 'string' } }
    }
  },
  {
    name: 'browse_page',
    description: 'Extract content from research URL',
    inputSchema: {
      type: 'object',
      properties: { url: { type: 'string' } }
    }
  }
];

const message = await client.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools,
  messages: [{ role: 'user', content: 'Research quantum computing breakthroughs 2024' }]
});

async function researchLoop(query: string) {
  let messages = [{ role: 'user', content: query }];

  while (true) {
    const msg = await client.messages.create({
      model: 'claude-3-5-sonnet-20240620',
      max_tokens: 1024,
      tools,
      messages
    });

    messages.push(msg);

    if (msg.stop_reason !== 'tool_use') break;

    // Execute tools and append results
    for (const tool of msg.tool_calls || []) {
      const result = await executeTool(tool);
      messages.push({
        role: 'user',
        content: [{ type: 'tool_result', tool_use_id: tool.id, content: result }]
      });
    }
  }
  return messages;
}

