import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: 'vex_key' });

async function verifyToolResults(toolCalls: any[]) {
  const verifiedResults = [];

  for (const toolCall of toolCalls) {
    const result = await executeTool(toolCall);

    const verification = await vex.verify({
      input: toolCall.input,
      output: result,
      checks: ['source_verification', 'recency_check'],
      policy: 'medium'
    });

    if (verification.status === 'pass') {
      verifiedResults.push({
        type: 'tool_result',
        tool_use_id: toolCall.id,
        content: verification.output
      });
    } else {
      console.warn(`Tool verification failed: ${verification.reason}`);
      // Retry logic
    }
  }

  return verifiedResults;
}

